#include <vector>
#include <algorithm>
#include <unordered_map>

using namespace std;

class UnionFind {
public:
    vector<int> parent;
    vector<int> rank;
    int components;

    UnionFind(int n) {
        parent.resize(n);
        rank.resize(n, 0);
        components = n;
        for (int i = 0; i < n; ++i) {
            parent[i] = i;
        }
    }

    int find(int u) {
        if (parent[u] != u) {
            parent[u] = find(parent[u]);
        }
        return parent[u];
    }

    void unite(int u, int v) {
        int rootU = find(u);
        int rootV = find(v);
        if (rootU != rootV) {
            if (rank[rootU] > rank[rootV]) {
                parent[rootV] = rootU;
            } else if (rank[rootU] < rank[rootV]) {
                parent[rootU] = rootV;
            } else {
                parent[rootV] = rootU;
                rank[rootU]++;
            }
            components--;
        }
    }
};

long long solve(long long n, std::vector<std::vector<long long>> edges, long long k) {
    if (k <= 1) return 0;
    if (k > n) return -1; // though problem says k <= n, but just in case

    sort(edges.begin(), edges.end(), [](const vector<long long>& a, const vector<long long>& b) {
        return a[2] < b[2];
    });

    UnionFind uf(n);
    long long left = 0;
    long long right = edges.empty() ? 0 : edges.back()[2];
    long long answer = 0;

    // Check if initial components >= k
    if (uf.components >= k) {
        return 0;
    }

    // Binary search for the minimal t
    while (left <= right) {
        long long mid = left + (right - left) / 2;
        UnionFind tempUF(n);
        for (const auto& edge : edges) {
            if (edge[2] > mid) {
                tempUF.unite(edge[0], edge[1]);
            }
        }
        if (tempUF.components >= k) {
            answer = mid;
            right = mid - 1;
        } else {
            left = mid + 1;
        }
    }

    return answer;
}

